import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }

interface Q {
  tier: string; exam: string; stem: string; options: string[];
  correct: number; rationale: string; diff: number; bs: string;
  topic: string; subtopic: string; tags: string[]; clinicalPearl: string;
}

function q(bs: string, d: number, s: string, o: string[], c: number, r: string, topic: string, subtopic: string, tags: string[], pearl: string): Q {
  return { tier: "rn", exam: "NCLEX-RN", stem: s, options: o, correct: c, rationale: r, diff: d, bs, topic, subtopic, tags, clinicalPearl: pearl };
}

const QS: Q[] = [
  // CARDIAC (10)
  q("Cardiovascular", 3, "A client with pericarditis reports chest pain that worsens when lying flat and improves when sitting up and leaning forward. The nurse should position the client:", ["Supine with legs elevated", "Sitting upright and leaning forward on an overbed table to reduce pericardial pressure", "In a left lateral position", "Prone"], 1, "Pericardial pain worsens when lying supine (pericardium rubs against the heart) and improves sitting upright and leaning forward (reduces heart-pericardial contact). This position also relieves the feeling of dyspnea. Other features: pericardial friction rub (pathognomonic), diffuse ST elevation on ECG, fever. Treatment: NSAIDs + colchicine. Avoid anticoagulants (risk of hemorrhagic pericarditis). Options A, C, and D worsen pain.", "Pericarditis", "Pain Management Positioning", ["cardiac", "pericarditis", "positioning", "pain"], "Pericarditis triad: chest pain (pleuritic, worse supine), friction rub, diffuse ST elevation. Treatment: NSAIDs + colchicine. AVOID anticoagulants. Cardiac tamponade complication: Beck's triad = hypotension, JVD, muffled heart sounds."),

  q("Cardiovascular", 4, "A nurse is interpreting hemodynamic monitoring. A client has a pulmonary artery wedge pressure (PAWP) of 22 mmHg. This indicates:", ["Normal left heart function", "Left ventricular failure with elevated left atrial and pulmonary pressures", "Right ventricular failure", "Hypovolemia"], 1, "Normal PAWP is 8-12 mmHg. PAWP reflects left atrial pressure and left ventricular end-diastolic pressure. Elevated PAWP (>18 mmHg) indicates left-sided heart failure, fluid overload, or mitral valve disease. Clinical correlation: pulmonary edema typically occurs at PAWP >18-20 mmHg. Treatment: diuretics, vasodilators, inotropes. Option A would show normal values. Option C would show elevated CVP. Option D would show low PAWP.", "Hemodynamic Monitoring", "PAWP Interpretation", ["cardiac", "PAWP", "hemodynamics", "heart-failure"], "Hemodynamic normals: CVP 2-8, PAP 20-30/8-15, PAWP 8-12, CO 4-8, CI 2.5-4.0. High PAWP = left HF. High CVP = right HF. Low CVP/PAWP = hypovolemia. High SVR = vasoconstriction. Low SVR = vasodilation (sepsis)."),

  q("Cardiovascular", 2, "A client is scheduled for a cardiac catheterization via the femoral artery. Post-procedure nursing care includes:", ["Immediate ambulation to prevent blood clots", "Maintaining the affected leg straight and immobile for 4-6 hours, monitoring the access site for bleeding, and assessing peripheral pulses", "Elevating the head of the bed to 90 degrees immediately", "No monitoring is needed"], 1, "Post-femoral cardiac catheterization: maintain affected leg straight for 4-6 hours (prevents bleeding from arterial puncture site), apply pressure dressing or closure device per protocol, monitor for bleeding/hematoma every 15 minutes initially, assess peripheral pulses (dorsalis pedis, posterior tibial) for embolism, monitor VS, and maintain adequate hydration to flush contrast dye. Option A risks bleeding. Option C may increase site pressure. Option D ignores significant risks.", "Cardiac Catheterization", "Post-Procedure Care", ["cardiac", "cardiac-cath", "post-procedure", "assessment"], "Post-cath femoral: flat x 4-6 hrs, sandbag on site per protocol, check pedal pulses q15min x 1hr then q30min x 2hr. Report: bleeding, loss of pulse, numbness/tingling, increasing pain, hematoma. Push fluids for contrast clearance."),

  // RESPIRATORY (5)
  q("Respiratory", 3, "A nurse is caring for a client with status asthmaticus who is not responding to initial bronchodilator therapy. The nurse should anticipate:", ["Discharge home with oral medications", "IV magnesium sulfate, continuous nebulized albuterol, systemic corticosteroids, and preparation for possible intubation", "Discontinuing all medications", "Oral bronchodilators only"], 1, "Status asthmaticus is a severe, life-threatening asthma exacerbation that does not respond to standard treatment. Escalation includes: continuous nebulized albuterol, IV magnesium sulfate (2g over 20 min — smooth muscle relaxation), systemic corticosteroids (IV methylprednisolone), oxygen, and preparation for intubation if respiratory failure develops. Heliox (helium-oxygen mixture) may be considered. ABG monitoring essential. Options A, C, and D are inadequate.", "Asthma", "Status Asthmaticus", ["respiratory", "status-asthmaticus", "emergency", "magnesium"], "Status asthmaticus: life-threatening. Treatment ladder: continuous albuterol + ipratropium → IV magnesium → IV terbutaline → heliox → intubation. Silent chest = ominous sign (no air movement). ABG: respiratory acidosis = impending failure."),

  q("Respiratory", 3, "A nurse is caring for a client on a ventilator using lung-protective ventilation (ARDSNet protocol). The nurse should maintain:", ["Tidal volume of 12-15 mL/kg of ideal body weight", "Tidal volume of 4-8 mL/kg of ideal body weight and plateau pressure below 30 cmH2O", "No specific tidal volume restrictions", "Peak inspiratory pressure above 40 cmH2O"], 1, "ARDSNet lung-protective ventilation protocol: low tidal volumes (4-8 mL/kg of IDEAL body weight — not actual weight), plateau pressure <30 cmH2O (prevents barotrauma), adequate PEEP (per PEEP/FiO2 table), and permissive hypercapnia if needed (tolerate PaCO2 up to 55-60 as long as pH >7.25). This strategy reduces ventilator-induced lung injury and mortality. Option A uses too-high volumes. Options C and D promote lung injury.", "ARDS", "Lung-Protective Ventilation", ["respiratory", "ARDS", "ventilation", "ARDSNet"], "ARDSNet protocol: TV 4-8 mL/kg IBW, Pplat <30 cmH2O, adequate PEEP, permissive hypercapnia acceptable. Reduces mortality by 22%. Use IDEAL body weight (based on height), NOT actual body weight. Prone positioning for severe ARDS (PaO2/FiO2 <150)."),

  // GI (5)
  q("Gastrointestinal", 3, "A client with a Sengstaken-Blakemore tube for esophageal variceal bleeding develops sudden respiratory distress. The nurse should first:", ["Increase the balloon pressure", "Cut the tube and remove it immediately to relieve potential airway obstruction from balloon migration", "Administer a bronchodilator", "Reassure the client"], 1, "The Sengstaken-Blakemore tube has an esophageal and gastric balloon. Balloon migration upward can cause airway obstruction — a life-threatening emergency. Emergency: scissors must be kept at the bedside at all times. If respiratory distress occurs, cut the tube to deflate all balloons and remove the tube immediately. This takes priority over all other interventions. Options A, C, and D delay lifesaving action.", "Variceal Bleeding", "Blakemore Tube Emergency", ["GI", "blakemore-tube", "airway-emergency", "varices"], "Blakemore tube: scissors at bedside ALWAYS. If respiratory distress: CUT the tube immediately. Check gastric balloon position with X-ray before inflating esophageal balloon. Maximum inflation time: 24-48 hrs (pressure necrosis risk)."),

  q("Gastrointestinal", 2, "A nurse is teaching a client about preventing gastroesophageal reflux disease (GERD) symptoms. The nurse should advise:", ["Lie down immediately after eating", "Elevate the head of bed 6-8 inches, avoid eating 2-3 hours before bedtime, lose weight if overweight, and avoid trigger foods", "Drink carbonated beverages to relieve symptoms", "Wear tight-fitting clothing around the abdomen"], 1, "GERD lifestyle modifications: elevate HOB 6-8 inches (gravity prevents reflux), avoid eating 2-3 hours before bedtime, weight loss, avoid trigger foods (spicy, fatty, citrus, chocolate, caffeine, alcohol, peppermint), small frequent meals, avoid tight clothing (increases intra-abdominal pressure), and smoking cessation. Options A, C, and D all worsen GERD symptoms.", "GERD", "Lifestyle Modifications", ["GI", "GERD", "reflux", "patient-education"], "GERD lifestyle: HOB elevation (6-8 inches, not just extra pillows), no late eating, weight loss, avoid triggers. Pharmacologic: PPI (most effective), H2 blockers. Chronic GERD: monitor for Barrett's esophagus (cancer risk)."),

  // RENAL (3)
  q("Renal/Urinary", 3, "A nurse is caring for a client with rhabdomyolysis. The priority intervention to prevent acute kidney injury is:", ["Restricting fluids to protect the kidneys", "Aggressive IV fluid resuscitation with normal saline to maintain urine output above 200-300 mL/hour", "Administering potassium supplements", "Encouraging oral fluids only"], 1, "Rhabdomyolysis releases myoglobin from damaged muscle, which precipitates in renal tubules causing AKI. Treatment: aggressive IV fluid resuscitation (NS at 200-1000 mL/hr initially) to maintain UO >200-300 mL/hr, flushing myoglobin through the kidneys. Sodium bicarbonate may be added to alkalinize urine (myoglobin is less nephrotoxic in alkaline urine). Monitor CK, potassium (hyperkalemia from cell lysis), and renal function. Option A worsens renal damage. Option C — K+ is already elevated. Option D is insufficient.", "Rhabdomyolysis", "AKI Prevention", ["renal", "rhabdomyolysis", "AKI", "fluid-resuscitation"], "Rhabdomyolysis triad: muscle pain, weakness, dark urine (tea/cola colored). CK >5x normal. Treatment: aggressive IV NS (maintain UO >200-300 mL/hr), bicarbonate to alkalinize urine, monitor for hyperkalemia, compartment syndrome, DIC. Common causes: crush injury, statins, extreme exercise, seizures."),

  // NEURO (3)
  q("Neurological", 3, "A nurse is preparing a client for a lumbar puncture. The nurse should position the client:", ["Sitting upright in a chair", "In a lateral recumbent position with knees drawn up to the chest and chin tucked, or sitting and leaning over a table", "Supine with legs extended", "Prone"], 1, "LP positioning: lateral recumbent (fetal position) with knees drawn to the chest and chin tucked — this opens the intervertebral spaces for needle insertion. Alternatively, sitting on the edge of the bed leaning forward over a bedside table. Post-LP: lie flat for 1-4 hours (per facility protocol) to reduce risk of post-LP headache. Push fluids. Report: persistent headache, fever, drainage from site, leg weakness or numbness. Options A, C, and D do not optimize intervertebral space access.", "Lumbar Puncture", "Positioning", ["neuro", "lumbar-puncture", "positioning", "procedures"], "LP positioning: fetal position (lateral) or sitting leaning forward. Post-LP: lie flat 1-4 hrs, push fluids. Post-LP headache: worse when upright, better lying down. Treatment: caffeine, analgesics, epidural blood patch for persistent headache."),

  q("Neurological", 3, "A client with a subarachnoid hemorrhage develops severe headache and neck stiffness 4 days after the initial bleed. The nurse suspects:", ["Normal recovery", "Vasospasm — a major complication occurring 4-14 days after SAH", "Rebleed", "Hydrocephalus"], 1, "Cerebral vasospasm is the most common cause of morbidity and mortality after SAH, occurring 4-14 days post-bleed (peak at days 7-10). Signs: worsening headache, neurological deterioration, focal deficits, and decreased LOC. Prevention: nimodipine (calcium channel blocker) started within 96 hours. Detection: transcranial Doppler (increased velocities), CTA, or cerebral angiography. Treatment: hypertensive therapy (induced hypertension), IV fluids, endovascular interventions. Options A and C do not fit the timeline. Option D presents differently.", "Subarachnoid Hemorrhage", "Vasospasm", ["neuro", "SAH", "vasospasm", "nimodipine"], "Post-SAH vasospasm: days 4-14 (peak 7-10). Prevention: nimodipine 60mg q4h x 21 days. Triple-H therapy (historical): Hypertension, Hypervolemia, Hemodilution. Current: induced hypertension + euvolemia. Monitor with transcranial Doppler."),

  // ENDOCRINE (3)
  q("Endocrine", 3, "A client with type 2 diabetes has been started on metformin. Before prescribing, the healthcare provider should assess:", ["Thyroid function only", "Renal function (eGFR), as metformin is contraindicated when eGFR falls below 30 mL/min", "Liver function only", "Cardiac enzymes"], 1, "Metformin is renally cleared and can accumulate to toxic levels in renal impairment, increasing the risk of lactic acidosis. Current guidelines: eGFR >45 mL/min = safe to start, eGFR 30-45 = dose reduction (do not exceed 1000 mg/day), eGFR <30 = contraindicated. Also hold for 48 hours before/after IV contrast dye procedures. Monitor B12 levels with long-term use. Options A, C, and D are incomplete assessments.", "Oral Hypoglycemics", "Metformin Renal Assessment", ["endocrine", "metformin", "renal-function", "lactic-acidosis"], "Metformin renal guidelines: eGFR >45 = full dose, 30-45 = max 1000mg/day, <30 = stop. Hold 48 hrs around IV contrast. Monitor B12 (deficiency with long-term use). Lactic acidosis: rare but fatal. No weight gain, possible weight loss."),

  q("Endocrine", 4, "A nurse is caring for a client in thyroid storm. Priority interventions include:", ["Oral thyroid hormone replacement", "Beta-blockers for tachycardia, propylthiouracil or methimazole to block thyroid hormone synthesis, iodine solution to block hormone release, cooling measures, and hydrocortisone", "Warming blankets and reduced monitoring", "Discharge with oral medications"], 1, "Thyroid storm is a life-threatening hyperthyroid emergency. Treatment sequence: 1) Beta-blocker (propranolol IV) for tachycardia, 2) Thionamide (PTU preferred — also blocks T4-to-T3 conversion), 3) Iodine solution (Lugol's or SSKI) — given 1 HOUR AFTER thionamide to prevent using the iodine to make more hormone, 4) Hydrocortisone (blocks T4-to-T3 conversion + prevents adrenal crisis), 5) Cooling measures (acetaminophen, cooling blankets — avoid aspirin which displaces T4 from binding proteins). ICU-level care. Options A, C, and D are inappropriate.", "Thyroid Storm", "Emergency Management", ["endocrine", "thyroid-storm", "hyperthyroidism", "emergency"], "Thyroid storm treatment order: Beta-blocker → PTU/methimazole → Iodine (1 hr AFTER thionamide) → Hydrocortisone → Cooling (NO aspirin). Triggers: surgery, infection, DKA, trauma in undiagnosed/untreated hyperthyroidism. Mortality 20-30% even with treatment."),

  // PHARMACOLOGY (21)
  q("Pharmacology", 3, "A client is prescribed naloxone (Narcan) for opioid overdose reversal. The nurse should know:", ["One dose provides permanent reversal", "Naloxone has a shorter half-life than most opioids and may need to be re-dosed every 2-3 minutes; monitor for return of respiratory depression", "Naloxone eliminates all opioid withdrawal symptoms", "Naloxone only works for fentanyl"], 1, "Naloxone duration of action is 30-90 minutes, while many opioids last much longer (morphine 4-5 hours, methadone 24+ hours, fentanyl patches 72 hours). Re-sedation and respiratory depression can recur when naloxone wears off. Dose: 0.4-2 mg IV/IM/SC every 2-3 minutes (max 10 mg). Titrate to respiratory rate >12, not full consciousness (to avoid precipitating severe withdrawal). Monitor for at least 2 hours. Option A ignores re-sedation risk. Option C — naloxone causes withdrawal. Option D — works for all opioids.", "Opioid Antagonists", "Naloxone Duration", ["pharmacology", "naloxone", "opioid-overdose", "respiratory-depression"], "Naloxone: shorter half-life than most opioids = re-sedation risk. Titrate to respirations, NOT full alertness (avoids severe withdrawal). IM naloxone auto-injector (Evzio) available for lay rescuers. Intranasal naloxone (Narcan nasal spray) for community use."),

  q("Pharmacology", 2, "A client is prescribed lisinopril. The nurse should teach the client to report:", ["Mild headache", "Persistent dry cough, as this is a common side effect of ACE inhibitors caused by bradykinin accumulation", "Improved blood pressure readings", "Normal appetite"], 1, "Dry cough occurs in 5-35% of patients on ACE inhibitors due to bradykinin accumulation in the lungs (ACE normally breaks down bradykinin). The cough is dry, nonproductive, and persistent. If intolerable, switch to an ARB (which does not affect bradykinin). Other side effects: hyperkalemia, angioedema (rare but serious), hypotension, and teratogenicity. Options A, C, and D are not concerning findings.", "ACE Inhibitors", "Dry Cough", ["pharmacology", "ACE-inhibitor", "lisinopril", "dry-cough"], "ACE inhibitor cough: dry, nonproductive, occurs in 5-35% of patients. More common in women and Asian patients. Resolves within 1-4 weeks of discontinuation. Alternative: ARB (no cough). Both are contraindicated in pregnancy."),

  q("Pharmacology", 3, "A client receiving aminoglycoside therapy (gentamicin) should be monitored for which two organ-specific toxicities?", ["Hepatotoxicity and cardiotoxicity", "Nephrotoxicity and ototoxicity", "Pulmonary toxicity and neurotoxicity", "Dermatologic toxicity and hematologic toxicity"], 1, "Aminoglycosides (gentamicin, tobramycin, amikacin) have two major dose-limiting toxicities: nephrotoxicity (damage to renal tubular cells — monitor BUN, creatinine) and ototoxicity (damage to CN VIII — hearing loss, tinnitus, vertigo). Monitor peak and trough levels, renal function, and hearing. Risk factors: prolonged therapy, high doses, concurrent nephrotoxic drugs, dehydration, and older age. Options A, C, and D are not the primary aminoglycoside toxicities.", "Antibiotics", "Aminoglycoside Toxicity", ["pharmacology", "aminoglycoside", "nephrotoxicity", "ototoxicity"], "Aminoglycosides: nephrotoxicity + ototoxicity. Monitor: peak (efficacy), trough (toxicity), BUN/Cr, hearing. Once-daily dosing reduces toxicity while maintaining efficacy. Avoid concurrent nephrotoxins (vancomycin, amphotericin B, NSAIDs)."),

  q("Pharmacology", 3, "A client with atrial fibrillation on warfarin therapy has an INR of 1.5. The nurse should:", ["Hold the warfarin as the INR is too high", "Notify the provider as the INR is subtherapeutic; the target for atrial fibrillation is 2.0-3.0", "Continue the current dose as the INR is therapeutic", "Administer vitamin K to lower the INR"], 1, "Target INR for atrial fibrillation is 2.0-3.0. An INR of 1.5 is subtherapeutic, meaning the client is not adequately anticoagulated and is at increased risk for stroke. The provider may increase the warfarin dose. Target INR for mechanical heart valves is higher (2.5-3.5). Options A and D would worsen subtherapeutic levels. Option C incorrectly identifies the level as therapeutic.", "Anticoagulant Therapy", "INR Monitoring", ["pharmacology", "warfarin", "INR", "atrial-fibrillation"], "Warfarin INR targets: AFib = 2.0-3.0, mechanical valve = 2.5-3.5. Subtherapeutic: increase dose. Supratherapeutic without bleeding: hold 1-2 doses, recheck. Supratherapeutic with bleeding: vitamin K + PCC/FFP. Check INR weekly until stable, then monthly."),

  q("Pharmacology", 3, "A nurse is teaching a client about levothyroxine (Synthroid). Proper administration includes:", ["Take at bedtime with a calcium supplement", "Take on an empty stomach 30-60 minutes before breakfast with water; separate from calcium, iron, and antacids by 4 hours", "Take with meals for better absorption", "Take only when feeling fatigued"], 1, "Levothyroxine absorption is significantly reduced by food, calcium, iron, antacids, and PPIs. Take first thing in the morning on an empty stomach with a full glass of water, and wait 30-60 minutes before eating. Separate from interfering substances by 4 hours. Take consistently at the same time daily. Monitor TSH levels every 6-8 weeks until stable, then annually. Options A, C, and D reduce effectiveness.", "Thyroid Replacement", "Levothyroxine Administration", ["pharmacology", "levothyroxine", "thyroid", "medication-timing"], "Levothyroxine: empty stomach, 30-60 min before food, separate from Ca/Fe/antacids by 4 hrs. Monitor TSH q6-8 weeks until stable. Narrow therapeutic index — brand changes may alter levels. Never abruptly stop. Takes 4-6 weeks for full effect."),

  q("Pharmacology", 2, "A client is prescribed ciprofloxacin. The nurse should advise:", ["Take with dairy products for better absorption", "Avoid dairy products and antacids near the dose time; report tendon pain immediately as fluoroquinolones can cause tendon rupture", "This medication has no musculoskeletal effects", "Take with iron supplements"], 1, "Fluoroquinolone (ciprofloxacin, levofloxacin) teaching: avoid dairy, antacids, calcium, iron, and zinc within 2 hours (chelation reduces absorption), report tendon pain immediately (risk of tendon rupture — especially Achilles tendon), use sunscreen (photosensitivity), and adequate hydration (prevent crystalluria). FDA black box warning: tendinitis/rupture, peripheral neuropathy, CNS effects. Avoid in children (cartilage damage). Options A and D reduce absorption. Option C is incorrect.", "Antibiotics", "Fluoroquinolone Safety", ["pharmacology", "ciprofloxacin", "tendon-rupture", "fluoroquinolone"], "Fluoroquinolone black box warnings: tendon rupture (stop immediately if tendon pain), peripheral neuropathy, CNS effects (seizures, confusion). Risk factors for tendon rupture: >60 years old, concurrent corticosteroids, renal failure, organ transplant."),

  q("Pharmacology", 3, "A client receiving chemotherapy develops tumor lysis syndrome. The nurse should anticipate:", ["No metabolic changes", "Hyperuricemia, hyperkalemia, hyperphosphatemia, and hypocalcemia; treatment with aggressive IV hydration, allopurinol or rasburicase, and electrolyte management", "Hypoglycemia and hyponatremia", "Metabolic alkalosis"], 1, "Tumor lysis syndrome (TLS) occurs when rapid cancer cell death releases intracellular contents: uric acid (hyperuricemia), potassium (hyperkalemia), phosphorus (hyperphosphatemia), and the elevated phosphorus binds calcium (hypocalcemia). Can cause acute kidney injury, cardiac arrhythmias, and seizures. Prevention: aggressive IV hydration, allopurinol or rasburicase (urate oxidase). Treatment: manage electrolytes, dialysis if needed. Options A, C, and D are incorrect metabolic profiles.", "Oncologic Emergencies", "Tumor Lysis Syndrome", ["pharmacology", "TLS", "oncology", "electrolytes"], "TLS electrolytes: high uric acid, high K+, high PO4, low Ca2+. Prevention: hydration + allopurinol. Rasburicase: breaks down uric acid (faster than allopurinol). Monitor: labs q4-6h during high-risk chemo. Highest risk: aggressive lymphomas, leukemias with high tumor burden."),

  q("Pharmacology", 2, "A client is prescribed metformin. The nurse should teach about the most serious adverse effect:", ["Weight gain", "Lactic acidosis, which is rare but potentially fatal; report muscle pain, weakness, difficulty breathing, and unusual fatigue", "Hypoglycemia as a common occurrence", "Diarrhea as the most dangerous effect"], 1, "Lactic acidosis is the most serious adverse effect of metformin, though rare (estimated 6-9 cases per 100,000 patient-years). Symptoms: muscle pain, weakness, malaise, dyspnea, abdominal discomfort, and hypothermia. Risk factors: renal impairment, hepatic disease, heart failure, excessive alcohol use, and contrast dye procedures. GI side effects (nausea, diarrhea) are the MOST COMMON but not the most serious. Option A — metformin is weight-neutral. Option C — metformin rarely causes hypoglycemia alone. Option D is common but not the most serious.", "Oral Hypoglycemics", "Metformin Lactic Acidosis", ["pharmacology", "metformin", "lactic-acidosis", "patient-education"], "Metformin: lactic acidosis rare but fatal. GI side effects most common (start low, titrate slowly, take with food). Benefits: no weight gain, no hypoglycemia as monotherapy, cardiovascular protection, low cost. First-line for T2DM."),

  q("Pharmacology", 3, "A client with bipolar disorder has a lithium level of 2.0 mEq/L. The nurse should:", ["Continue the medication at the current dose", "Hold the medication immediately and notify the provider — this level is toxic", "Increase the dose for better effect", "Administer the next dose on schedule"], 1, "Lithium therapeutic range is 0.6-1.2 mEq/L (maintenance). A level of 2.0 mEq/L is toxic. Lithium toxicity signs: GI (nausea, vomiting, diarrhea at 1.5-2.0), neurological (tremor, confusion, ataxia at 2.0-2.5), and life-threatening (seizures, coma, renal failure at >2.5). Treatment: hold lithium, aggressive IV hydration (NS to promote renal excretion), hemodialysis for severe toxicity (>2.5 or symptomatic). Options A, C, and D risk life-threatening toxicity.", "Mood Stabilizers", "Lithium Toxicity", ["pharmacology", "lithium", "toxicity", "bipolar"], "Lithium levels: therapeutic 0.6-1.2, toxic >1.5. Early toxicity: GI symptoms, fine tremor. Moderate: coarse tremor, confusion, muscle twitching. Severe: seizures, coma, cardiac arrhythmias. Treatment: IV NS, dialysis if >2.5. Monitor: levels, renal function, thyroid, electrolytes."),

  q("Pharmacology", 3, "A client is prescribed IV phenytoin. The nurse should administer:", ["Mixed in dextrose solution", "In normal saline only (phenytoin precipitates in dextrose), at a rate no faster than 50 mg/min in adults with continuous cardiac monitoring", "As a rapid IV push", "Without cardiac monitoring"], 1, "IV phenytoin compatibility: NS ONLY (precipitates in dextrose solutions). Maximum infusion rate: 50 mg/min in adults (25 mg/min in elderly or those with cardiac disease). Requires cardiac monitoring (risk of bradycardia, hypotension, and cardiac arrest with rapid infusion). Use an inline filter (crystallization). Fosphenytoin (Cerebyx) is a safer alternative — can be mixed in D5W or NS, given faster, and has less cardiovascular risk. Options A, C, and D are dangerous.", "Anticonvulsants", "IV Phenytoin Safety", ["pharmacology", "phenytoin", "IV-safety", "cardiac-monitoring"], "IV phenytoin: NS ONLY, max 50 mg/min (25 in elderly), cardiac monitor required, inline filter. Purple glove syndrome: rare extravasation causing limb ischemia. Fosphenytoin: safer alternative (any IV solution, faster rate, less cardiovascular risk)."),

  q("Pharmacology", 2, "A client taking an SSRI (sertraline) should be cautioned about combining it with:", ["Acetaminophen", "St. John's Wort, tramadol, or other serotonergic medications due to risk of serotonin syndrome", "Calcium supplements", "Multivitamins"], 1, "Serotonin syndrome occurs when excessive serotonin accumulates due to drug interactions. Combinations to avoid: SSRIs + MAOIs (most dangerous), SSRIs + SNRIs, SSRIs + tramadol, SSRIs + triptans, SSRIs + St. John's Wort, SSRIs + linezolid, SSRIs + lithium. Symptoms: mental status changes, autonomic instability (hyperthermia, tachycardia, diaphoresis), neuromuscular excitability (clonus, hyperreflexia, tremor). Treatment: discontinue offending agents, cyproheptadine. Options A, C, and D do not cause serotonin syndrome.", "Antidepressants", "Serotonin Syndrome Prevention", ["pharmacology", "SSRI", "serotonin-syndrome", "drug-interactions"], "Serotonin syndrome triad: mental status changes + autonomic instability + neuromuscular excitability. Distinguishing feature: clonus (especially lower extremity). Treatment: stop drugs, cyproheptadine (serotonin antagonist), supportive care. 14-day washout between MAOI and SSRI."),

  q("Pharmacology", 3, "A nurse is administering oxytocin (Pitocin) for labor augmentation. The nurse should monitor for:", ["Hypoglycemia", "Uterine tachysystole (more than 5 contractions in 10 minutes), fetal distress, and water intoxication", "Hyperglycemia", "Hypokalemia"], 1, "Oxytocin risks: uterine tachysystole (hyperstimulation — >5 contractions in 10 minutes or prolonged contractions), leading to decreased uteroplacental perfusion and fetal distress. Water intoxication (oxytocin has antidiuretic properties — can cause hyponatremia with prolonged high-dose infusion). Monitor: continuous fetal heart rate monitoring, contraction frequency/duration/intensity, maternal VS, and I&O. If tachysystole: turn off oxytocin, position left lateral, give oxygen, IV bolus. Options A, C, and D are not primary oxytocin concerns.", "Oxytocin", "Labor Monitoring", ["pharmacology", "oxytocin", "labor", "uterine-monitoring"], "Oxytocin: always via infusion pump, piggyback to main IV (can discontinue quickly). Monitor FHR continuously. Tachysystole: stop oxytocin, left lateral, O2, IV fluid bolus, consider terbutaline (tocolytic). Water intoxication: restrict free water, monitor Na+."),

  q("Pharmacology", 3, "A client is prescribed apixaban (Eliquis) for DVT treatment. The nurse should know the reversal agent is:", ["Protamine sulfate", "Andexanet alfa (Andexxa) — the specific reversal agent for factor Xa inhibitors", "Vitamin K", "Idarucizumab"], 1, "Andexanet alfa (Andexxa) is the FDA-approved reversal agent for factor Xa inhibitors (apixaban and rivaroxaban). It is a modified recombinant factor Xa protein that acts as a decoy, binding and sequestering the anticoagulant. Protamine reverses heparin. Vitamin K reverses warfarin. Idarucizumab (Praxbind) reverses dabigatran (direct thrombin inhibitor). Each anticoagulant has its own specific reversal strategy.", "Anticoagulant Therapy", "DOAC Reversal", ["pharmacology", "apixaban", "reversal-agent", "andexanet-alfa"], "DOAC reversal agents: Dabigatran → Idarucizumab (Praxbind). Apixaban/Rivaroxaban → Andexanet alfa (Andexxa). Also: 4-factor PCC may be used if specific reversal agents are unavailable. Warfarin → Vitamin K + PCC/FFP. Heparin → Protamine sulfate."),

  q("Pharmacology", 2, "A client prescribed a transdermal scopolamine patch for motion sickness should be taught:", ["Apply the patch to the forearm", "Apply behind the ear 4 hours before travel, wash hands thoroughly after application, and remove after 72 hours", "The patch works immediately", "Apply multiple patches for severe symptoms"], 1, "Transdermal scopolamine (anticholinergic): apply behind the ear on clean, dry, hairless skin. Allow 4 hours before travel for adequate drug absorption. Wash hands thoroughly after handling (touching the eyes can cause pupil dilation and blurred vision). Replace every 72 hours for continued protection. Side effects: dry mouth, drowsiness, blurred vision, urinary retention. Options A (wrong location), C (needs 4 hours), and D (overdose risk) are incorrect.", "Antiemetics", "Scopolamine Patch", ["pharmacology", "scopolamine", "motion-sickness", "transdermal"], "Scopolamine patch: behind ear, 4 hrs before travel. Wash hands after application (eye contamination = mydriasis). Max 72 hrs per patch. Anticholinergic effects: dry mouth, blurred vision, urinary retention. Contraindicated: glaucoma, GI obstruction, urinary retention."),

  q("Pharmacology", 3, "A client receiving amphotericin B for a systemic fungal infection should be monitored for:", ["Hepatotoxicity as the primary concern", "Nephrotoxicity (most common serious adverse effect), infusion-related reactions (fever, chills, rigors), and electrolyte abnormalities (hypokalemia, hypomagnesemia)", "No significant side effects", "Cardiotoxicity"], 1, "Amphotericin B ('amphoterrible') is known for its significant toxicity profile. Most serious: nephrotoxicity (occurs in up to 80% of patients — monitor BUN, creatinine). Infusion reactions: fever, chills, rigors (premedicate with acetaminophen, diphenhydramine, meperidine for rigors). Electrolyte wasting: hypokalemia, hypomagnesemia (renal tubular damage). Pre-hydrate with NS to reduce nephrotoxicity. Liposomal formulations reduce toxicity. Options A, C, and D are not the primary concerns.", "Antifungals", "Amphotericin B Toxicity", ["pharmacology", "amphotericin-B", "nephrotoxicity", "antifungal"], "Amphotericin B: 'amphoterrible.' Pre-hydrate with NS (nephroprotective). Premedicate: acetaminophen + diphenhydramine ± meperidine (for rigors). Monitor: BUN/Cr, K+, Mg2+, CBC. Liposomal formulations: less nephrotoxic, more expensive. Infuse over 2-6 hours."),

  q("Pharmacology", 3, "A client in the ICU is prescribed dexmedetomidine (Precedex) for sedation. A unique advantage of this medication is:", ["It provides deep sedation like propofol", "It provides cooperative sedation where the patient can be aroused for neurological assessments without respiratory depression", "It has no cardiovascular effects", "It works faster than propofol"], 1, "Dexmedetomidine is an alpha-2 agonist that provides 'cooperative sedation' — the patient is calm and sedated but can be easily aroused for neurological assessments and follow commands. Unique advantage: does NOT cause significant respiratory depression (unlike propofol and benzodiazepines). Side effects: bradycardia and hypotension. Ideal for: patients requiring frequent neuro checks, ventilator weaning, and delirium management. Options A — provides lighter sedation. Option C — causes bradycardia/hypotension. Option D is not accurate.", "ICU Sedation", "Dexmedetomidine Advantages", ["pharmacology", "dexmedetomidine", "sedation", "cooperative-sedation"], "Dexmedetomidine: cooperative sedation (arousable), no respiratory depression, reduces delirium incidence. Side effects: bradycardia, hypotension. Not for deep sedation needs. Ideal for: neuro ICU, ventilator weaning, procedural sedation in spontaneously breathing patients."),

  // ADDITIONAL MED-SURG AND PHARM TO REACH 510+
  q("Cardiovascular", 3, "A client is diagnosed with infective endocarditis. The nurse should assess for which classic finding?", ["Absent pedal pulses", "Splinter hemorrhages in the nailbeds, Janeway lesions, and Osler nodes", "Barrel chest", "Butterfly rash"], 1, "Infective endocarditis involves infection of the heart valves. Classic peripheral findings: splinter hemorrhages (linear red-brown streaks in the nailbeds), Janeway lesions (painless erythematous lesions on palms/soles), Osler nodes (painful, pea-sized nodules on fingertips/toes), Roth spots (retinal hemorrhages), and petechiae. Major concern: septic emboli to brain, kidneys, spleen, lungs. Treatment: prolonged IV antibiotics (4-6 weeks). Option A is PAD. Option C is COPD. Option D is lupus.", "Endocarditis", "Clinical Findings", ["cardiac", "endocarditis", "assessment", "emboli"], "Endocarditis findings: Janeway (painless, palms/soles), Osler (painful, fingers/toes). Remember: FROM JANE = Fever, Roth spots, Osler nodes, Murmur (new), Janeway lesions, Anemia, Nail bed hemorrhages, Emboli."),

  q("Respiratory", 3, "A nurse is preparing a client for a bronchoscopy. Which pre-procedure instruction is most important?", ["Eat a large meal before the procedure", "Maintain NPO status for 6-8 hours before the procedure and explain that the throat will be anesthetized", "No preparation is needed", "Take aspirin before the procedure for pain prevention"], 1, "Bronchoscopy pre-procedure care: NPO for 6-8 hours (aspiration risk from sedation and topical anesthetic), verify informed consent, remove dentures, baseline vital signs. Post-procedure: NPO until gag reflex returns (2-4 hours), semi-Fowler's position, monitor for: respiratory distress, hemoptysis, subcutaneous emphysema (sign of perforation), and fever. Option A increases aspiration risk. Option C is incorrect. Option D increases bleeding risk.", "Bronchoscopy", "Pre-Procedure Care", ["respiratory", "bronchoscopy", "pre-procedure", "NPO"], "Bronchoscopy: NPO 6-8 hrs, remove dentures. Post: NPO until gag returns (test with sips of water). Monitor for complications: bleeding, bronchospasm, pneumothorax, laryngospasm. Specimen may be sent for cytology, culture, biopsy."),

  q("Gastrointestinal", 3, "A nurse is caring for a client with a T-tube after cholecystectomy. Normal expected drainage in the first 24 hours is:", ["No drainage expected", "500-1000 mL of green-brown bile drainage", "Clear serous fluid only", "Bright red blood"], 1, "T-tube (placed in the common bile duct) drains bile while the duct heals after surgery. Normal drainage: 500-1000 mL/day initially, decreasing to 200 mL/day by one week. Color: green-brown (bile). The tube is typically clamped before meals (to allow bile to enter the duodenum for digestion) and then unclamped. Monitor: drainage amount, color, consistency. Report: sudden decrease (obstruction), increased amount, or purulent drainage. Options A, C, and D are not expected findings.", "Cholecystectomy", "T-Tube Management", ["GI", "T-tube", "cholecystectomy", "bile-drainage"], "T-tube: green-brown bile, 500-1000 mL initially. Clamp before meals (bile assists digestion), unclamp after. Keep below gallbladder level. Protect skin around tube (bile is corrosive). Cholangiogram may be done through T-tube before removal."),

  q("Renal/Urinary", 3, "A client with an arteriovenous fistula (AVF) for hemodialysis asks about caring for the access. The nurse should teach:", ["Blood pressure can be taken on the arm with the AVF", "Do not allow blood pressure measurements, IV insertions, or blood draws on the AVF arm; palpate for thrill and auscultate for bruit daily", "Wear tight sleeves over the AVF", "The AVF requires no special care"], 1, "AVF care: DO NOT use the access arm for BP measurement, venipuncture, or IV insertion (risk of damage, thrombosis, or infection). Check the access daily: palpate for thrill (vibration indicating blood flow) and auscultate for bruit (rushing sound). No restrictive clothing or jewelry on the access arm. Avoid sleeping on the arm. Report: absence of thrill/bruit, swelling, redness, or drainage. Options A, C, and D risk fistula damage.", "Hemodialysis Access", "AVF Care", ["renal", "AVF", "hemodialysis", "access-care"], "AVF: thrill = palpable vibration (blood flow), bruit = audible rushing sound. Both should be present. Absent = clotted access (emergency). Maturation: 2-3 months before use. Buttonhole technique or rope-ladder technique for cannulation."),

  q("Neurological", 3, "A client with bacterial meningitis is placed on droplet precautions. The nurse should also assess for signs of:", ["Hyperglycemia", "Increased intracranial pressure (headache, altered LOC, vomiting) and Waterhouse-Friderichsen syndrome (adrenal hemorrhage from meningococcal sepsis)", "Hypotension only", "Peripheral neuropathy"], 1, "Bacterial meningitis complications: increased ICP (from inflammation and cerebral edema), seizures, hearing loss (CN VIII damage), and Waterhouse-Friderichsen syndrome (bilateral adrenal hemorrhage from meningococcal septicemia — presents with petechial/purpuric rash, DIC, and shock). Kernig's sign (pain with knee extension) and Brudzinski's sign (neck flexion causes hip flexion) are classic meningeal signs. Options A, C, and D are incomplete.", "Meningitis", "Complications", ["neuro", "meningitis", "ICP", "waterhouse-friderichsen"], "Bacterial meningitis: lumbar puncture shows: elevated WBC (neutrophils), elevated protein, decreased glucose, elevated opening pressure. Treatment: empiric antibiotics IMMEDIATELY (do not wait for LP results). Prophylaxis for close contacts (rifampin or ciprofloxacin)."),

  q("Endocrine", 3, "A client with Addison's disease develops a crisis triggered by infection. The nurse should expect to administer:", ["Oral hydrocortisone only", "IV hydrocortisone bolus, aggressive IV normal saline for volume replacement, and vasopressors if needed", "Insulin for hyperglycemia", "IV dextrose only"], 1, "Addisonian crisis (adrenal crisis) is a life-threatening emergency caused by acute cortisol and aldosterone deficiency. Triggers: infection, surgery, trauma, or abrupt withdrawal of exogenous steroids. Treatment: IV hydrocortisone 100mg bolus then 50mg q8h, aggressive IV NS (dehydration and hyponatremia), IV dextrose (hypoglycemia is common), vasopressors if hypotension persists. Monitor: glucose, sodium, potassium, VS. Option A is too slow. Options C and D are incomplete.", "Addisonian Crisis", "Emergency Treatment", ["endocrine", "addisons", "adrenal-crisis", "emergency"], "Addisonian crisis: severe hypotension, hyponatremia, hyperkalemia, hypoglycemia. IV hydrocortisone + aggressive NS. Prevent by teaching patients to never stop steroids abruptly and to double dose during illness (stress dosing). Medical alert bracelet essential."),

  q("Pharmacology", 3, "A client is prescribed acetylcysteine (Mucomyst). The nurse should know this medication is used both as:", ["An antibiotic and an analgesic", "A mucolytic to thin respiratory secretions AND as the antidote for acetaminophen overdose", "A bronchodilator and an anti-inflammatory", "A cough suppressant and an antihistamine"], 1, "Acetylcysteine has two distinct clinical uses: 1) Mucolytic — breaks disulfide bonds in mucus, thinning secretions in respiratory conditions (COPD, CF, pneumonia). Given via nebulizer. 2) Acetaminophen antidote — replenishes glutathione stores in the liver, preventing hepatotoxicity. Given IV (loading dose over 1 hour, then 2 subsequent infusions over 20 hours) or oral (72-hour protocol). Most effective within 8 hours of acetaminophen ingestion. Options A, C, and D are incorrect.", "Mucolytics/Antidotes", "Acetylcysteine Dual Use", ["pharmacology", "acetylcysteine", "mucolytic", "acetaminophen-antidote"], "Acetylcysteine: mucolytic (nebulized) + acetaminophen antidote (IV or PO). For overdose: most effective within 8 hrs but can be given up to 72 hrs. Nomogram (Rumack-Matthew) determines treatment need based on level and time since ingestion."),

  q("Pharmacology", 3, "A nurse is teaching a client about the medication spironolactone for heart failure. The client asks about food restrictions. The nurse should advise:", ["Eat plenty of bananas and oranges for potassium", "Avoid excessive high-potassium foods and salt substitutes as spironolactone causes potassium retention", "No dietary modifications needed", "Increase sodium intake"], 1, "Spironolactone blocks aldosterone, causing sodium excretion and potassium retention. Hyperkalemia is the most dangerous adverse effect. Teaching: avoid high-potassium foods in excess (bananas, oranges, potatoes, tomatoes, spinach, avocados), avoid salt substitutes (contain KCl), and avoid potassium supplements unless specifically prescribed. Monitor serum K+ regularly. Option A increases hyperkalemia risk. Options C and D are incorrect.", "Aldosterone Antagonists", "Dietary Restrictions", ["pharmacology", "spironolactone", "hyperkalemia", "dietary-restrictions"], "Spironolactone dietary teaching: limit K+-rich foods, NO salt substitutes. Monitor K+ within 1 week of starting, then regularly. Risk increases with ACE-I/ARB combination, CKD, NSAID use. Target K+ 4.0-5.0 mEq/L."),

  q("Pharmacology", 3, "A client is prescribed vancomycin. The nurse should monitor which lab value to assess for the most significant adverse effect?", ["Blood glucose", "Serum creatinine and BUN for nephrotoxicity, and trough levels to guide dosing", "Hemoglobin A1C", "Thyroid function tests"], 1, "Vancomycin's most significant adverse effects are nephrotoxicity and ototoxicity. Monitor: serum creatinine and BUN (renal function), vancomycin trough levels (target 10-20 mcg/mL for most infections, 15-20 mcg/mL for serious infections like bacteremia/endocarditis). AUC/MIC-guided dosing is now preferred over trough-only monitoring. Also monitor for Red Man Syndrome (infuse over ≥60 min). Options A, C, and D are not relevant.", "Antibiotics", "Vancomycin Monitoring", ["pharmacology", "vancomycin", "nephrotoxicity", "trough-levels"], "Vancomycin monitoring: trough before 4th dose, target 10-20 mcg/mL. AUC/MIC monitoring preferred (target AUC 400-600). Nephrotoxicity risk increases with: concurrent aminoglycosides, high trough levels, prolonged therapy, dehydration. Infuse over ≥60 min (prevents Red Man Syndrome)."),

  q("Pharmacology", 2, "A client asks about the difference between scheduled pain medication and PRN pain medication. The nurse should explain:", ["PRN is more effective for chronic pain management", "Scheduled medications are given at regular intervals for consistent pain control; PRN is given as needed for breakthrough pain", "There is no difference", "Scheduled medications should only be used in the hospital"], 1, "Scheduled (around-the-clock) dosing maintains consistent blood levels, preventing the peaks and valleys of pain that occur with PRN-only dosing. This approach is superior for chronic pain management. PRN medications are used for breakthrough pain — episodes that 'break through' the baseline pain control. The WHO pain ladder recommends ATC dosing with PRN rescue doses. Options A (opposite), C, and D are incorrect.", "Pain Management", "ATC vs PRN Dosing", ["pharmacology", "pain-management", "ATC-dosing", "PRN"], "ATC vs PRN: ATC (around-the-clock) maintains steady blood levels, better for chronic pain. PRN for breakthrough pain. WHO ladder: Step 1 (non-opioid), Step 2 (weak opioid + non-opioid), Step 3 (strong opioid + non-opioid). Adjuvant medications at any step."),

  q("Musculoskeletal", 3, "A nurse is caring for a client in Buck's traction for a hip fracture before surgery. The weight should:", ["Rest on the floor when the client is in bed", "Hang freely off the end of the bed without touching the floor or bed frame", "Be removed during sleep", "Be increased whenever the client reports pain"], 1, "Traction principles: weights must hang freely (not resting on floor, bed, or frame), maintain the line of pull (rope should be aligned with the affected limb), maintain counter-traction (elevate the foot of bed or position the client to prevent sliding), check knots (secure but not resting on pulleys), and perform neurovascular checks distal to the traction. Buck's traction uses 5-8 lbs for temporary stabilization before hip surgery. Options A, C, and D compromise traction effectiveness.", "Traction", "Traction Principles", ["musculoskeletal", "traction", "hip-fracture", "nursing-care"], "Traction: weights hang free, maintain line of pull, counter-traction, check ropes/knots/pulleys. Buck's (skin traction): 5-8 lbs, boot applied to leg. Skeletal traction: pin through bone (heavier weight). Never remove skeletal traction. Pin care per protocol."),

  q("Immunological", 3, "A nurse is caring for a client in anaphylaxis. The first medication to administer is:", ["Diphenhydramine IV", "Epinephrine IM (intramuscular) into the vastus lateralis (anterolateral thigh)", "Albuterol nebulizer", "IV methylprednisolone"], 1, "Anaphylaxis first-line treatment is EPINEPHRINE IM (0.3-0.5 mg of 1:1000 concentration in adults). Inject into the anterolateral thigh (vastus lateralis) for fastest absorption. May repeat every 5-15 minutes. Second-line: IV fluids (NS bolus), diphenhydramine, ranitidine, albuterol for bronchospasm, corticosteroids (prevent biphasic reaction). Options A, C, and D are important but are second-line to epinephrine.", "Anaphylaxis", "First-Line Treatment", ["immunology", "anaphylaxis", "epinephrine", "emergency"], "Anaphylaxis: epinephrine IM FIRST (vastus lateralis). Repeat q5-15min PRN. IV access, NS bolus. Second-line: antihistamines, corticosteroids. Observe 4-6 hours (biphasic reaction). Prescribe EpiPen at discharge. Refer to allergist."),

  q("Hematology", 3, "A nurse is caring for a client with sickle cell disease experiencing a vaso-occlusive crisis. Priority interventions include:", ["Cold compresses to the affected area", "IV fluid hydration, aggressive pain management with opioids, oxygen therapy, and rest", "Restricting fluids", "Applying tourniquets to affected limbs"], 1, "Vaso-occlusive (pain) crisis is caused by sickled RBCs blocking blood flow. Priority treatment: aggressive IV hydration (reduces blood viscosity), adequate pain management (typically IV opioids — do not undertreat), oxygen therapy (prevents further sickling), rest, and treating precipitating factors (infection, dehydration, cold). Hydroxyurea for chronic management reduces crisis frequency. Options A (cold worsens sickling), C (dehydration triggers crisis), and D (worsens ischemia) are harmful.", "Sickle Cell Disease", "Vaso-Occlusive Crisis", ["hematology", "sickle-cell", "pain-crisis", "hydration"], "Sickle cell crisis: IV fluids + opioids (never undertreat pain) + O2 + rest. Triggers: dehydration, hypoxia, cold, infection, stress, altitude. Hydroxyurea: increases fetal hemoglobin, reduces crisis frequency. Acute chest syndrome: chest pain + infiltrate = emergency."),

  q("Cardiovascular", 3, "A nurse assesses a client post-cardiac catheterization via the radial artery. The nurse should monitor:", ["Femoral pulses bilaterally", "The radial pulse distal to the site, Allen's test result documentation, hemostasis device or pressure band function", "Only blood pressure in the contralateral arm", "Pupil reaction"], 1, "Radial approach cardiac catheterization: assess radial pulse distal to access site, ensure TR Band (radial compression device) is functioning correctly, check for hand ischemia (pallor, pain, numbness), verify adequate ulnar collateral flow (Allen's test performed pre-procedure), monitor the site for bleeding/hematoma. Advantages over femoral: earlier ambulation, fewer vascular complications, shorter hospital stay. Options A, C, and D miss the critical assessment.", "Cardiac Catheterization", "Radial Approach", ["cardiac", "cardiac-cath", "radial-access", "assessment"], "Radial approach: Allen's test before procedure (verify ulnar collateral flow). TR Band for hemostasis. Ambulation immediately post-procedure. Monitor: radial pulse, hand perfusion, device function. Lower bleeding risk than femoral."),

  q("Respiratory", 2, "A nurse is teaching a client with newly diagnosed asthma about medication use. The rescue inhaler (albuterol) should be used:", ["Every 4 hours on a schedule regardless of symptoms", "As needed for acute symptoms (wheezing, shortness of breath, chest tightness); if using more than 2 days per week, controller medication should be adjusted", "Only at bedtime", "Only during exercise"], 1, "Albuterol (SABA) is a rescue/reliever medication used for acute symptoms. The need for rescue inhaler >2 days/week indicates uncontrolled asthma requiring step-up of controller therapy (ICS). Controller medications (ICS, LABA) are taken daily regardless of symptoms. Using rescue inhaler before exercise for exercise-induced bronchoconstriction is also appropriate. Options A and C are incorrect scheduled use. Option D is too limited.", "Asthma", "Rescue vs Controller", ["respiratory", "asthma", "albuterol", "self-management"], "Asthma rescue vs controller: Rescue (albuterol) = PRN for acute symptoms. Controller (ICS) = daily regardless of symptoms. Using rescue >2 days/week = poorly controlled asthma, step up therapy. Step-up/step-down per NAEPP guidelines."),

  q("Gastrointestinal", 3, "A client is being evaluated for appendicitis. The nurse assesses McBurney's point, which is located:", ["In the left lower quadrant", "One-third the distance from the right anterior superior iliac spine to the umbilicus", "At the umbilicus", "In the epigastric region"], 1, "McBurney's point is the classic location of maximal tenderness in appendicitis, located one-third the distance from the right ASIS to the umbilicus. Other appendicitis findings: rebound tenderness, Rovsing's sign (palpation of left lower quadrant causes RLQ pain), psoas sign, obturator sign, and low-grade fever. Options A, C, and D are incorrect locations.", "Appendicitis", "Assessment", ["GI", "appendicitis", "McBurneys-point", "assessment"], "Appendicitis assessment: McBurney's point tenderness, rebound tenderness, Rovsing's sign, guarding. Do NOT apply heat (rupture risk). Pre-op: NPO, IV fluids, antibiotics. Ruptured appendicitis: peritonitis signs (rigid abdomen, high fever)."),

  q("Renal/Urinary", 2, "A nurse is teaching a client about the purpose of a 24-hour urine collection. The nurse should instruct:", ["Collect only the first morning void", "Discard the first void, then collect ALL urine for the next 24 hours including the final void at the end of the collection period; keep refrigerated", "Collect random samples throughout the day", "Only collect urine during waking hours"], 1, "24-hour urine collection technique: discard the first morning void (the bladder contents represent the previous collection period), note the time, then collect ALL urine for exactly 24 hours, including the void at the end of the 24-hour period. Keep the collection container refrigerated or on ice. Common tests: creatinine clearance, protein, cortisol, catecholamines. If any void is accidentally discarded, restart the entire collection. Options A, C, and D result in inaccurate results.", "Urinalysis", "24-Hour Collection", ["renal", "24-hour-urine", "diagnostics", "patient-education"], "24-hour urine: discard first void, collect everything for 24 hrs, include last void. Refrigerate. If one void is missed: restart. Common uses: creatinine clearance (GFR estimation), proteinuria quantification, cortisol, catecholamines (pheochromocytoma)."),

  q("Neurological", 2, "A nurse is caring for a client who had a generalized tonic-clonic seizure. During the seizure, the nurse should:", ["Restrain the client's limbs to prevent injury", "Protect the head, clear the area of hazards, turn to the side when possible, do NOT insert anything into the mouth, and time the seizure", "Insert a padded tongue blade between the teeth", "Administer oral medications during active seizure"], 1, "Seizure management: protect from injury (pad head, remove hazards, lower to floor if standing), do NOT restrain (causes fractures), do NOT put anything in the mouth (causes injury), turn to side when convulsions stop (prevents aspiration), time the seizure (>5 minutes = status epilepticus — administer benzodiazepine), and stay with the client. Post-ictal: maintain airway, orient the client, perform neuro assessment. Options A, C, and D cause harm.", "Seizure Disorders", "Seizure Management", ["neuro", "seizure", "safety", "first-aid"], "Seizure first aid: protect, don't restrain, nothing in mouth, turn to side, time it. Status epilepticus: >5 min or repeated seizures without regaining consciousness. Treatment: IV lorazepam or diazepam. Post-ictal: confusion, fatigue, headache normal — document duration."),

  q("Endocrine", 2, "A client with diabetes asks about the purpose of rotating insulin injection sites. The nurse explains:", ["Rotation is not important", "Rotating sites prevents lipodystrophy (lipohypertrophy or lipoatrophy) which can impair insulin absorption", "Rotation makes injections less painful", "Only rotate between arms"], 1, "Repeated insulin injection in the same site causes lipodystrophy: lipohypertrophy (fatty lumps — most common) or lipoatrophy (indentations). These tissue changes impair insulin absorption, leading to erratic blood glucose levels. Rotate within the same general area (e.g., within the abdomen) for consistency of absorption rates between doses. Different body areas have different absorption rates: abdomen (fastest) > arms > thighs > buttocks. Options A, C, and D are incorrect or incomplete.", "Insulin Administration", "Site Rotation", ["endocrine", "diabetes", "insulin", "injection-technique"], "Insulin rotation: rotate within same region (abdomen preferred for consistency). Absorption rates: abdomen > arms > thighs > buttocks. Lipohypertrophy: avoid injecting into lumps (erratic absorption). Inspect sites regularly. Use each injection spot only once per month."),

  q("Pharmacology", 3, "A client is prescribed benztropine (Cogentin) for extrapyramidal symptoms caused by haloperidol. The nurse should monitor for:", ["Diarrhea and excessive salivation", "Anticholinergic effects: dry mouth, urinary retention, constipation, blurred vision, and tachycardia", "Bradycardia and hypotension", "Increased parkinsonian symptoms"], 1, "Benztropine is an anticholinergic medication used to treat drug-induced EPS (dystonia, pseudoparkinsonism). Anticholinergic side effects (can't see, can't pee, can't spit, can't...): blurred vision, urinary retention, dry mouth, constipation, tachycardia, mydriasis, and confusion (especially in elderly). Contraindicated in glaucoma and BPH. Option A describes cholinergic effects (opposite). Option C is not typical. Option D would indicate treatment failure.", "Anticholinergics", "Benztropine Monitoring", ["pharmacology", "benztropine", "anticholinergic", "EPS-treatment"], "Anticholinergic effects mnemonic: Blind as a bat (mydriasis), Dry as a bone (dry mouth), Red as a beet (flushing), Hot as a hare (hyperthermia), Mad as a hatter (confusion), Full as a flask (urinary retention). Use caution in elderly (delirium risk)."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const item of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14}::text[],$${idx+15})`);
      params.push(
        item.tier, item.exam, "multiple_choice", "published",
        item.stem, JSON.stringify(item.options), JSON.stringify([item.correct]),
        item.rationale, item.diff, item.bs, "BOTH", hash(item.stem),
        item.topic, item.subtopic, "{" + item.tags.join(",") + "}", item.clinicalPearl
      );
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, tags, clinical_pearl)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,tags,clinical_pearl)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
    console.log(`[RN-MedSurg-Pharm-B7] Batch ${Math.floor(i/batchSize)+1}: inserted ${result.rowCount || 0} questions`);
  }
  console.log(`\n[RN-MedSurg-Pharm-B7] Total inserted: ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));

  const bodySys = await pool.query(`SELECT body_system, count(*) as cnt FROM exam_questions WHERE tier='rn' AND status='published' GROUP BY body_system ORDER BY cnt DESC LIMIT 30`);
  console.log(`\nRN Body System Distribution:`);
  bodySys.rows.forEach((r: any) => console.log(`  ${r.body_system || '(null)'}: ${r.cnt}`));

  const total = await pool.query(`SELECT count(*) as cnt FROM exam_questions WHERE tier='rn' AND status='published'`);
  console.log(`\nTotal RN published questions: ${total.rows[0].cnt}`);

  await pool.end();
}

main().catch(e => { console.error(e); process.exit(1); });
